frappe.ui.form.on('Quotation', {
    setup: function(frm) {
        frm.set_query('custom_project', function() {
            return {
                filters: {
                    customer: frm.doc.party_name
                }
            };
        });
    },
    party_name: function(frm) {
        if (frm.doc.custom_project) {
            frappe.db.get_value('Customer Projects', frm.doc.custom_project, 'customer')
                .then(r => {
                    if (r.message && r.message.customer !== frm.doc.party_name) {
                        frm.set_value('custom_project', '');
                    }
                });
        }
    }
});

frappe.ui.form.on('Project Contact Link', {
    contact: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (row.contact) {
            frappe.db.get_doc('Contact', row.contact).then(doc => {
                let full_name = [doc.first_name, doc.last_name].filter(Boolean).join(' ');
                frappe.model.set_value(cdt, cdn, 'full_name', full_name);

                let mobile = (doc.phone_nos || []).find(p => p.is_primary_mobile_no) 
                          || (doc.phone_nos || [])[0];
                frappe.model.set_value(cdt, cdn, 'mobile_no', mobile ? mobile.phone : '');

                let email = (doc.email_ids || []).find(e => e.is_primary) 
                         || (doc.email_ids || [])[0];
                frappe.model.set_value(cdt, cdn, 'email_id', email ? email.email_id : '');
            });
        }
    }
});

frappe.ui.form.on('Project Address Link', {
    address: function(frm, cdt, cdn) {
        let row = locals[cdt][cdn];
        if (row.address) {
            frappe.db.get_doc('Address', row.address).then(doc => {
                frappe.model.set_value(cdt, cdn, 'address_title', doc.address_title);
                frappe.model.set_value(cdt, cdn, 'address_type', doc.address_type);
                frappe.model.set_value(cdt, cdn, 'city', doc.city);
                frappe.model.set_value(cdt, cdn, 'phone', doc.phone);
            });
        }
    }
});

