// =============================================================================
// Noyan LOM — Client Script (v3)
// - List Type (Normal / LOM) toggles the LOM sections
// - Spaces.floor is a Select fed from the Floors table
// - Native-style matrices (look like Frappe grids)
// - Product matrix auto-syncs item_code + qty into the standard Items table
// Create TWO Client Script records with this SAME code:
//   1) DocType = Quotation   · Enabled
//   2) DocType = Sales Order  · Enabled
// =============================================================================
(function () {
  const DELIM = "\u00A7"; // § — separates floor and space inside a column key

  const LOM_FIELDS = [
    "custom_lom_floors", "custom_lom_spaces",
    "custom_lom_cat_head", "custom_lom_category_matrix",
    "custom_lom_prod_head", "custom_lom_product_matrix",
  ];

  // ---- mode ----------------------------------------------------------------
  function isLom(frm) {
    let m = frm.doc.custom_list_type;
    if (!m) {
      const hasData =
        (frm.doc.custom_lom_products || []).length ||
        (frm.doc.custom_lom_floors || []).length;
      m = hasData ? "LOM" : "Normal";
      frm.doc.custom_list_type = m; // silent default, don't dirty
      frm.refresh_field("custom_list_type");
    }
    return m === "LOM";
  }

  function applyMode(frm) {
    frm.toggle_display(LOM_FIELDS, isLom(frm));
  }

  // ---- columns from Spaces -------------------------------------------------
  function colKey(floor, space) {
    return `${floor}${DELIM}${space}`;
  }

  function getColumns(frm) {
    const spaces = (frm.doc.custom_lom_spaces || []).filter(
      (s) => (s.floor || "").trim() && (s.space || "").trim()
    );
    const groups = [];
    const byFloor = {};
    spaces.forEach((s) => {
      const f = s.floor.trim();
      const sp = s.space.trim();
      if (!byFloor[f]) {
        byFloor[f] = { floor: f, cols: [] };
        groups.push(byFloor[f]);
      }
      byFloor[f].cols.push({ floor: f, space: sp, key: colKey(f, sp) });
    });
    const flat = [];
    groups.forEach((g) => g.cols.forEach((c) => flat.push(c)));
    return { groups, flat };
  }

  // ---- cell helpers --------------------------------------------------------
  function parseCells(row) {
    const c = row.cell_data;
    if (c && typeof c === "object") return c;
    try {
      return JSON.parse(c || "{}") || {};
    } catch (e) {
      return {};
    }
  }

  function recompute(frm, row, flatCols) {
    const cells = parseCells(row);
    let total = 0;
    flatCols.forEach((c) => {
      total += flt(cells[c.key]);
    });
    frappe.model.set_value(row.doctype, row.name, "total_qty", total);
  }

  // ---- Spaces.floor Select options -----------------------------------------
  function buildFloorOptions(frm) {
    const floors = (frm.doc.custom_lom_floors || [])
      .map((f) => (f.floor_name || "").trim())
      .filter(Boolean);
    const optStr = ["", ...floors].join("\n");
    const grid = frm.fields_dict.custom_lom_spaces && frm.fields_dict.custom_lom_spaces.grid;
    if (grid) {
      grid.update_docfield_property("floor", "options", optStr);
      grid.refresh();
    }
  }

  // ---- auto-sync product matrix -> Items (item_code + qty) -----------------
  let _syncTimer = null;
  function scheduleSync(frm) {
    clearTimeout(_syncTimer);
    _syncTimer = setTimeout(() => syncItems(frm), 400);
  }

  async function syncItems(frm) {
    if (!isLom(frm) || frm.doc.docstatus !== 0) return;

    const totals = {};
    (frm.doc.custom_lom_products || []).forEach((r) => {
      if (r.item_code && flt(r.total_qty) > 0) {
        totals[r.item_code] = (totals[r.item_code] || 0) + flt(r.total_qty);
      }
    });

    // drop item rows that are no longer in the LOM
    frm.doc.items = (frm.doc.items || []).filter(
      (r) => r.item_code && totals[r.item_code] != null
    );

    // update existing, add missing
    for (const code of Object.keys(totals)) {
      let row = (frm.doc.items || []).find((r) => r.item_code === code);
      if (!row) {
        row = frm.add_child("items");
        await frappe.model.set_value(row.doctype, row.name, "item_code", code);
      }
      await frappe.model.set_value(row.doctype, row.name, "qty", totals[code]);
    }
    frm.refresh_field("items");
  }

  // ---- native-ish grid styling --------------------------------------------
  const STYLE = `
    <style>
      .lom-wrap{overflow-x:auto;border:1px solid var(--border-color);border-radius:var(--border-radius-md,6px);background:var(--fg-color,#fff)}
      table.lom{border-collapse:collapse;font-size:var(--text-sm,12px);min-width:100%;color:var(--text-color)}
      table.lom th,table.lom td{border:1px solid var(--border-color);padding:6px 8px;text-align:center;white-space:nowrap}
      table.lom thead th{background:var(--gray-100,#f4f5f6);color:var(--text-muted,#6b7280);font-weight:500}
      table.lom th.lom-floor{background:var(--gray-200,#e9ebed);color:var(--text-color)}
      table.lom td.lom-left{text-align:left}
      table.lom td.lom-total{font-weight:600;background:var(--gray-100,#f4f5f6)}
      table.lom tbody tr:hover{background:var(--gray-50,#fafbfc)}
      table.lom input{width:60px;text-align:center;border:1px solid transparent;background:transparent;border-radius:var(--border-radius,4px);padding:2px 4px;color:var(--text-color)}
      table.lom input:focus{border-color:var(--primary,#5e64ff);background:var(--fg-color,#fff);outline:none}
      .lom-x{cursor:pointer;color:var(--text-muted);font-weight:700;font-size:14px}
      .lom-x:hover{color:var(--red-500,#c0392b)}
      .lom-bar{margin:0 0 8px}
      .lom-empty{padding:12px;color:var(--text-muted);font-style:italic}
    </style>`;

  // ---- render one matrix ---------------------------------------------------
  function renderMatrix(frm, kind) {
    const isProduct = kind === "product";
    const tableField = isProduct ? "custom_lom_products" : "custom_lom_categories";
    const htmlField = isProduct ? "custom_lom_product_matrix" : "custom_lom_category_matrix";
    const field = frm.fields_dict[htmlField];
    if (!field) return;
    const $w = field.$wrapper;

    const { groups, flat } = getColumns(frm);
    const rows = frm.doc[tableField] || [];
    const editable = frm.doc.docstatus === 0;
    const addLabel = isProduct ? __("Add Product") : __("Add Category");

    let html = STYLE;
    html += `<div class="lom-bar">
      <button class="btn btn-xs btn-default lom-add" ${editable ? "" : "disabled"}>+ ${addLabel}</button>
    </div>`;

    if (!flat.length) {
      html += `<div class="lom-empty">${__("Define floors and spaces first.")}</div>`;
      $w.html(html);
      $w.find(".lom-add").off("click").on("click", () => addRow(frm, kind));
      return;
    }

    html += `<div class="lom-wrap"><table class="lom"><thead><tr>`;
    if (isProduct) html += `<th rowspan="2">${__("Item")}</th>`;
    else html += `<th rowspan="2">${__("Category")}</th>`;
    groups.forEach((g) => {
      html += `<th class="lom-floor" colspan="${g.cols.length}">${frappe.utils.escape_html(g.floor)}</th>`;
    });
    html += `<th rowspan="2">${__("Total")}</th><th rowspan="2"></th></tr><tr>`;
    flat.forEach((c) => {
      html += `<th>${frappe.utils.escape_html(c.space)}</th>`;
    });
    html += `</tr></thead><tbody>`;

    rows.forEach((row) => {
      const cells = parseCells(row);
      html += `<tr data-cdn="${row.name}">`;
      const label = isProduct ? row.item_name || row.item_code || "" : row.category || "";
      html += `<td class="lom-left">${frappe.utils.escape_html(label)}</td>`;
      flat.forEach((c) => {
        const v = cells[c.key] != null ? cells[c.key] : "";
        html += `<td><input type="number" class="lom-cell" data-cdn="${row.name}" data-key="${frappe.utils.escape_html(c.key)}" value="${v}" ${editable ? "" : "disabled"}></td>`;
      });
      html += `<td class="lom-total" data-total="${row.name}">${row.total_qty || 0}</td>`;
      html += `<td>${editable ? `<span class="lom-x" data-remove="${row.name}">&times;</span>` : ""}</td>`;
      html += `</tr>`;
    });

    html += `</tbody></table></div>`;
    $w.html(html);

    $w.find(".lom-add").off("click").on("click", () => addRow(frm, kind));

    $w.find(".lom-cell").off("change").on("change", function () {
      const cdn = $(this).data("cdn");
      const key = String($(this).data("key"));
      const row = (frm.doc[tableField] || []).find((r) => r.name === cdn);
      if (!row) return;
      const cells = parseCells(row);
      const val = flt($(this).val());
      if (val) cells[key] = val;
      else delete cells[key];
      frappe.model.set_value(row.doctype, row.name, "cell_data", JSON.stringify(cells));
      recompute(frm, row, flat);
      $w.find(`[data-total="${cdn}"]`).text(row.total_qty || 0);
      if (isProduct) scheduleSync(frm);
    });

    $w.find(".lom-x").off("click").on("click", function () {
      const cdn = $(this).data("remove");
      frm.doc[tableField] = (frm.doc[tableField] || []).filter((r) => r.name !== cdn);
      frm.dirty();
      frm.refresh_field(tableField);
      renderMatrix(frm, kind);
      if (isProduct) scheduleSync(frm);
    });
  }

  function addRow(frm, kind) {
    if (kind === "product") {
      frappe.prompt(
        { label: __("Item"), fieldname: "item", fieldtype: "Link", options: "Item", reqd: 1 },
        (v) => {
          const row = frm.add_child("custom_lom_products", { cell_data: "{}" });
          frappe.model.set_value(row.doctype, row.name, "item_code", v.item);
          frappe.db.get_value("Item", v.item, ["item_name", "description"]).then((r) => {
            const d = (r && r.message) || {};
            frappe.model.set_value(row.doctype, row.name, "item_name", d.item_name || v.item);
            frappe.model.set_value(row.doctype, row.name, "description", d.description || "");
            renderMatrix(frm, "product");
          });
        },
        __("Add Product"), __("Add")
      );
    } else {
      frappe.prompt(
        { label: __("Category"), fieldname: "category", fieldtype: "Link", options: "LOM Category", reqd: 1 },
        (v) => {
          frm.add_child("custom_lom_categories", { category: v.category, cell_data: "{}" });
          frm.dirty();
          renderMatrix(frm, "category");
        },
        __("Add Category"), __("Add")
      );
    }
  }

  function renderAll(frm) {
    buildFloorOptions(frm);
    renderMatrix(frm, "category");
    renderMatrix(frm, "product");
  }

  // ---- parent events -------------------------------------------------------
  const parentEvents = {
    refresh(frm) {
      applyMode(frm);
      renderAll(frm);
    },
    custom_list_type(frm) {
      applyMode(frm);
      if (isLom(frm)) {
        renderAll(frm);
        scheduleSync(frm);
      }
    },
    custom_lom_floors_add(frm) { buildFloorOptions(frm); },
    custom_lom_floors_remove(frm) { renderAll(frm); },
    custom_lom_spaces_add(frm) { renderAll(frm); },
    custom_lom_spaces_remove(frm) { renderAll(frm); },
    validate(frm) { renderAll(frm); },
  };

  frappe.ui.form.on("Quotation", parentEvents);
  frappe.ui.form.on("Sales Order", parentEvents);

  // ---- child events (bind once) -------------------------------------------
  if (!window.__noyan_lom_v3) {
    window.__noyan_lom_v3 = true;
    frappe.ui.form.on("LOM Floor", {
      floor_name(frm) { buildFloorOptions(frm); },
    });
    frappe.ui.form.on("LOM Space", {
      floor(frm) { renderAll(frm); },
      space(frm) { renderAll(frm); },
    });
  }
})();

